import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"血刃","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/血刃.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/血刃.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/血刃.md"};function l(i,e,_,p,c,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"血刃",tabindex:"-1"},[n("血刃 "),a("a",{class:"header-anchor",href:"#血刃","aria-label":'Permalink to "血刃"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="血刃-1" tabindex="-1">血刃 <a class="header-anchor" href="#血刃-1" aria-label="Permalink to &quot;血刃&quot;">​</a></h1><p>战灰：血刃</p><p>价格：D+1000<br> 描述：《艾尔登法环》世界中存在的能赋予武器属性，战技的战灰之一。在取得时需要选定自身持有的一个武器，将战灰赋予其上。只有在装备那个武器时，才可以使用战灰的战技。<br> 这个战灰仅可以附着在轻剑与匕首上。<br> 一柄武器仅可以被赋予一个战灰。战灰所选定的武器可以在一次长休时进行变更。<br> 【血】：战灰所附带的属性之一，附加该属性的武器在攻击检定上承受6dp的器械减值。<br> 每次你以此武器进行攻击并且命中，你都会为对方累计一层“出血”，每层“出血”视同为传奇感知点的以你附加本战灰的武器的伤害类型为类型的易伤。<br> 这个易伤并不会立刻生效，而是累计，直到出血的层数大于等于对方的传奇感知，这时你的下一次攻击会使得累计的全部出血层数立刻生效，并且消失，需要重新进行累计。<br> 【战技：血刃】：自伤后用血液沾染武器，释放能引发出血的血刃的战技。可以连续施放。<br> 以一个标准动作，消耗1点意志。你将自己的武器染上血液，然后将血刃挥洒而出。流失的血液将会使你受到不可避免的2点严重伤害。<br> 这次攻击具有15米的射程，并且具有2点攻击上的亵渎加值。<br> 血刃可以进行连续射出，只要上回合你使用过了血刃，本轮你继续使用血刃攻击并且命中后，可以额外给对手累计一层“出血”。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',5)])])}const f=r(d,[["render",l]]);export{m as __pageData,f as default};
